INSERT INTO `bug_reports` (`id`, `type`, `subject`, `description`, `name`, `email`, `user_id`, `status`, `admin_notes`, `resolved_at`, `created_at`, `updated_at`) VALUES
(1, 'feature', 'dodati br stola na kome se igra', 'stol na kome se igra bi trebao biti kao parametar na meču jer ga treba birati na osnovu slobodnog mjesta. neki mečevi se brže završe pa je na turniru bitno da se primjeti da je stol slobodan i da ga se dodjeli sljedećem meču koji se igra. (Mada to i sudija prijavi kad završi meč). Obično na početku sudija bude vezan uz stol dok su svi stolovi popunjeni, al mislim da se sudije kasnije biraju po iskustvu ako je meč ozbiljniji', NULL, NULL, 4, 'resolved', NULL, '2025-10-23 10:26:09', '2025-10-22 13:48:22', '2025-10-23 10:26:09'),
(2, 'bug', 'dodatna grupa', 'kreirao turnir sa 8 grupa a trebalo sa 9. mogu dodati još jednu grupu ali kad odem da unesem devetu ovih prvih 8 ponovo prazno', NULL, NULL, 4, 'resolved', NULL, '2025-10-28 22:37:53', '2025-10-28 13:16:04', '2025-10-28 22:37:53'),
(3, 'feature', 'scroll na grupama', 'scroll na grupama ako može da pamti poziciju nakon unešenog rezultata meča', NULL, NULL, 4, 'resolved', NULL, '2025-10-28 22:37:34', '2025-10-28 16:24:53', '2025-10-28 22:37:34'),
(4, 'bug', 'ne radi upgrade plan', 'sdads', NULL, NULL, 1, 'closed', NULL, '2025-11-01 20:37:14', '2025-11-01 20:36:49', '2025-11-01 20:37:14'),
(5, 'bug', 'EDITOVANJE GRUPA', 'kod editovanja grupa ne zapamti redoslijed predhodno spašene grupe', NULL, NULL, 4, 'resolved', NULL, '2025-12-23 19:47:57', '2025-11-28 10:22:40', '2025-12-23 19:47:57');
