(2, 'Padel', 'padel', 'Sport koji kombinuje elemente tenisa, skvoša i badmintona u zatvorenom terenu.', '🎾', '1', '2025-10-17 22:55:21', '2025-10-17 22:55:36', '{\"game_type\":\"sets_games\",\"sets_to_win\":2,\"games_per_set\":6,\"tie_break_at\":6,\"serve_change_every\":1,\"deuce\":true,\"time_limits\":null,\"players_per_team\":2,\"scoring\":{\"point_values\":[15,30,40,\"game\"],\"special_rules\":\"Tie-break at 6-6\"}}', '0'),
(3, 'Tenis', 'tenis', 'Klasični sport sa reketom i loptom koji se igra na terenu sa mrežom.', '🎾', '1', '2025-10-17 22:55:21', '2025-10-17 22:55:37', '{\"game_type\":\"sets_games\",\"sets_to_win\":2,\"games_per_set\":6,\"tie_break_at\":6,\"serve_change_every\":1,\"deuce\":true,\"time_limits\":null,\"players_per_team\":1,\"scoring\":{\"point_values\":[15,30,40,\"game\"],\"special_rules\":\"Tie-break at 6-6, 3 sets to win match\"}}', '0'),
(4, 'Košarka', 'kosarka', 'Dinamični timski sport gdje se lopta ubacuje u koš.', '🏀', '1', '2025-10-17 22:55:21', '2025-10-17 22:55:40', '{\"game_type\":\"time_based\",\"periods\":4,\"period_duration\":600,\"overtime\":true,\"players_per_team\":5,\"max_players_on_court\":5,\"scoring\":{\"point_values\":[1,2,3],\"special_rules\":\"2 points for field goal, 3 points for three-pointer, 1 point for free throw\"}}', '0'),
(5, 'Mali Fudbal', 'mali-fudbal', 'Brzi timski sport koji se igra u zatvorenom prostoru sa 5 igrača po timu.', '⚽', '1', '2025-10-17 22:55:21', '2025-10-17 22:55:38', '{\"game_type\":\"time_based\",\"periods\":2,\"period_duration\":1200,\"overtime\":false,\"players_per_team\":5,\"max_players_on_court\":5,\"scoring\":{\"point_values\":[1],\"special_rules\":\"1 goal = 1 point, offside rule applies\"}}', '0');
